public class ProgressChecker {
  public static void main(String[] args) {
    // 学習進捗の確認
    int totalDays = 10;
    int studiedDays = 7;

    for (int i = 1; i <= studiedDays; i++) {
      System.out.println("学習ログ Day " + i);
    }

    int rate = studiedDays / totalDays * 100;
    System.out.println("Rate: " + rate + "%");

    if (rate >= 70) {
      System.out.println("順調です");
    } else {
      System.out.println("もう少し頑張ろう");
    }
  }
}

