class Task {
  private String title;
  private boolean done;

  public Task(String title) {
    this.title = title;
    this.done = false;
  }

  public void complete() {
    done = true;
  }

  public void show() {
    String status = done ? "[DONE]" : "[TODO]";
    System.out.println(status + " " + title);
  }
}

public class App {
  public static void main(String[] args) {
    Task[] tasks = new Task[3];

    tasks[0] = new Task("Java復習");
    tasks[1] = new Task("レポート作成");
    tasks[2] = new Task("運動");

    tasks[0].complete();

    for (int i = 0; i < tasks.length; i++) {
      tasks[i].show();
    }
  }
}
